INSERT INTO entries (lang, lb_id, difficulty, page, title, tags, summary, content, eg_in, eg_out) VALUES
('python', 136, 'intermediate', 1, 'os.path 模块路径操作', '["标准库","os","文件路径"]', '介绍os.path模块用于处理文件路径的常见函数。', 'os.path模块提供了一系列函数来操作文件路径。例如os.path.join()用于连接路径，os.path.abspath()用于获取绝对路径，os.path.exists()检查路径是否存在。这些函数跨平台兼容，简化了文件系统操作。', '["import os\\npath = os.path.join(\\"dir\\", \\"file.txt\\")\\nprint(path)", "import os\\nabs_path = os.path.abspath(\\".\\")\\nprint(abs_path)", "import os\\nif os.path.exists(\\"file.txt\\"):\\n    print(\\"文件存在\\")"]', '["dir/file.txt", "/current/directory", "文件存在"]'),
('python', 137, 'intermediate', 1, 'sys 模块系统参数', '["标准库","sys","系统"]', '使用sys模块访问和操作Python解释器相关的系统参数。', 'sys模块提供了与Python解释器交互的函数和变量，如sys.argv用于获取命令行参数，sys.path用于模块搜索路径，sys.exit()用于退出程序。它还包含系统特定的配置信息。', '["import sys\\nprint(sys.argv)", "import sys\\nprint(sys.path)", "import sys\\nsys.exit(0)"]', '["[\\"script.py\\", \\"arg1\\"]", "[\\"/usr/lib/python3.8\\", \\".\\"]", ""]'),
('python', 138, 'intermediate', 1, 'json 模块数据序列化', '["标准库","json","序列化"]', '学习使用json模块进行JSON数据的编码和解码。', 'json模块允许将Python对象（如字典、列表）转换为JSON字符串（序列化），以及将JSON字符串解析为Python对象（反序列化）。常用函数包括json.dumps(), json.loads(), json.dump(), json.load()。', '["import json\\ndata = {\\"name\\": \\"John\\", \\"age\\": 30}\\njson_str = json.dumps(data)\\nprint(json_str)", "import json\\njson_str = \\"[{\\\"x\\\": 1, \\\"y\\\": 2}]\\"\\nparsed = json.loads(json_str)\\nprint(parsed[0][\\"x\\"])"]', '["{\\"name\\": \\"John\\", \\"age\\": 30}", "1"]'),
('python', 139, 'intermediate', 1, 're 模块正则表达式', '["标准库","re","正则表达式"]', '掌握re模块进行字符串匹配和替换的正则表达式操作。', 're模块提供了正则表达式匹配功能，支持搜索、匹配、查找和替换。常用函数有re.search(), re.match(), re.findall(), re.sub()，以及编译正则对象提高性能。', '["import re\\npattern = r\\"\\\\d+\\"\\ntext = \\"There are 123 apples\\"\\nmatch = re.search(pattern, text)\\nif match:\\n    print(match.group())", "import re\\ntext = \\"hello world\\"\\nnew_text = re.sub(r\\"world\\", \\"Python\\", text)\\nprint(new_text)"]', '["123", "hello Python"]'),
('python', 140, 'intermediate', 1, 'datetime 模块日期时间', '["标准库","datetime","时间"]', '使用datetime模块处理日期和时间数据。', 'datetime模块提供了日期和时间相关的类，如datetime.date, datetime.datetime, datetime.timedelta。它可以进行日期计算、格式化和解析，适用于时间戳操作和时区处理（需结合pytz）。', '["from datetime import datetime\\nnow = datetime.now()\\nprint(now)", "from datetime import timedelta\\ndelta = timedelta(days=5)\\nprint(now + delta)"]', '["2023-10-01 12:00:00.000000", "2023-10-06 12:00:00.000000"]'),
('python', 141, 'intermediate', 1, 'collections 模块容器类型', '["标准库","collections","数据结构"]', '介绍collections模块中的专用容器数据类型，如defaultdict和Counter。', 'collections模块提供了额外的容器类型，如defaultdict（带默认值的字典）、Counter（计数器）、deque（双端队列）、OrderedDict（有序字典）和namedtuple（命名元组），优化特定用例。', '["from collections import defaultdict\\nd = defaultdict(int)\\nd[\\"a\\"] += 1\\nprint(d)", "from collections import Counter\\ncounter = Counter([\\"a\\", \\"b\\", \\"a\\", \\"c\\"])\\nprint(counter)"]', '["defaultdict(<class \\"int\\">, {\\"a\\": 1})", "Counter({\\"a\\": 2, \\"b\\": 1, \\"c\\": 1})"]'),
('python', 142, 'intermediate', 1, 'itertools 模块迭代工具', '["标准库","itertools","迭代器"]', '学习itertools模块提供的迭代器构建工具。', 'itertools模块包含一系列用于操作迭代器的函数，如itertools.chain()（连接迭代器）、itertools.cycle()（循环迭代）、itertools.combinations()（组合）、itertools.islice()（切片），提升迭代效率。', '["import itertools\\nfor i in itertools.islice(itertools.count(), 5):\\n    print(i)", "import itertools\\ncomb = list(itertools.combinations([1,2,3], 2))\\nprint(comb)"]', '["0\\n1\\n2\\n3\\n4", "[(1, 2), (1, 3), (2, 3)]"]'),
('python', 143, 'intermediate', 1, 'functools 模块高阶函数', '["标准库","functools","函数式编程"]', '使用functools模块中的高阶函数和装饰器。', 'functools模块提供了用于高阶函数的工具，如functools.partial（部分函数）、functools.lru_cache（缓存装饰器）、functools.wraps（保留元数据），支持函数式编程和性能优化。', '["from functools import partial\\ndef multiply(x, y):\\n    return x * y\\ndouble = partial(multiply, 2)\\nprint(double(5))", "from functools import lru_cache\\n@lru_cache(maxsize=None)\\ndef fib(n):\\n    if n < 2:\\n        return n\\n    return fib(n-1) + fib(n-2)\\nprint(fib(10))"]', '["10", "55"]'),
('python', 144, 'intermediate', 1, 'argparse 模块命令行解析', '["标准库","argparse","命令行"]', '掌握argparse模块解析命令行参数。', 'argparse模块使得编写用户友好的命令行接口变得简单，支持定义位置参数、可选参数、类型转换、帮助信息和子命令，自动生成帮助文档。', '["import argparse\\nparser = argparse.ArgumentParser(description=\\"Example\\")\\nparser.add_argument(\\"input\\", help=\\"input file\\")\\nargs = parser.parse_args([\\"file.txt\\"])\\nprint(args.input)", "import argparse\\nparser = argparse.ArgumentParser()\\nparser.add_argument(\\"--verbose\\", action=\\"store_true\\")\\nargs = parser.parse_args([\\"--verbose\\"])\\nprint(args.verbose)"]', '["file.txt", "True"]'),
('python', 145, 'intermediate', 1, 'logging 模块日志记录', '["标准库","logging","日志"]', '学习使用logging模块进行应用程序日志记录。', 'logging模块提供了灵活的日志记录系统，支持不同日志级别（DEBUG、INFO、WARNING等）、处理器（如文件、控制台）和格式化器，便于调试和监控应用程序。', '["import logging\\nlogging.basicConfig(level=logging.INFO)\\nlogging.info(\\"This is an info message\\")", "import logging\\nlogger = logging.getLogger(__name__)\\nlogger.warning(\\"This is a warning\\")"]', '["INFO:root:This is an info message", "WARNING:__main__:This is a warning"]'),
('python', 146, 'intermediate', 1, 'subprocess 模块进程管理', '["标准库","subprocess","进程"]', '使用subprocess模块运行外部命令和管理子进程。', 'subprocess模块允许生成新进程，连接到其输入/输出/错误管道，并获取返回码。常用函数有subprocess.run()、subprocess.Popen()，支持同步和异步操作。', '["import subprocess\\nresult = subprocess.run([\\"echo\\", \\"hello\\"], capture_output=True, text=True)\\nprint(result.stdout)", "import subprocess\\nsubprocess.call([\\"ls\\", \\"-l\\"])"]', '["hello\\n", ""]'),
('python', 147, 'intermediate', 1, 'threading 模块多线程', '["标准库","threading","并发"]', '介绍threading模块实现多线程编程。', 'threading模块提供了线程相关的操作，允许程序同时运行多个任务，包括线程创建、同步（如锁、信号量）和通信，但受GIL限制，适合I/O密集型任务。', '["import threading\\ndef worker():\\n    print(\\"Thread working\\")\\nt = threading.Thread(target=worker)\\nt.start()\\nt.join()", "import threading\\nlock = threading.Lock()\\nwith lock:\\n    print(\\"Lock acquired\\")"]', '["Thread working", "Lock acquired"]'),
('python', 148, 'intermediate', 1, 'multiprocessing 模块多进程', '["标准库","multiprocessing","并行"]', '学习multiprocessing模块实现多进程编程。', 'multiprocessing模块使用子进程而非线程来绕过GIL，实现真正的并行计算，支持进程池、队列和共享内存，适用于CPU密集型任务。', '["from multiprocessing import Process\\ndef f(name):\\n    print(f\\"Hello {name}\\")\\np = Process(target=f, args=(\\"World\\",))\\np.start()\\np.join()", "from multiprocessing import Pool\\ndef square(x):\\n    return x*x\\nwith Pool(5) as p:\\n    print(p.map(square, [1,2,3]))"]', '["Hello World", "[1, 4, 9]"]'),
('python', 149, 'intermediate', 1, 'asyncio 模块异步IO', '["标准库","asyncio","异步"]', '掌握asyncio模块进行异步编程。', 'asyncio模块提供了编写单线程并发代码的框架，使用async/await语法，基于事件循环处理I/O操作，适用于高并发网络应用。', '["import asyncio\\nasync def main():\\n    print(\\"Hello\\")\\n    await asyncio.sleep(1)\\n    print(\\"World\\")\\nasyncio.run(main())", "import asyncio\\nasync def fetch():\\n    await asyncio.sleep(2)\\n    return \\"data\\"\\nresult = asyncio.run(fetch())\\nprint(result)"]', '["Hello\\nWorld", "data"]'),
('python', 150, 'intermediate', 1, 'pathlib 模块面向对象路径', '["标准库","pathlib","文件路径"]', '使用pathlib模块以面向对象的方式处理文件路径。', 'pathlib模块提供了表示文件系统路径的类（如Path），具有直观的方法和属性，用于路径拼接、解析、文件操作和通配符匹配，替代传统os.path。', '["from pathlib import Path\\np = Path(\\"dir/file.txt\\")\\nprint(p.name)", "from pathlib import Path\\np = Path(\\".\\")\\nfor file in p.glob(\\"*.py\\"):\\n    print(file)"]', '["file.txt", "script.py\\nanother.py"]');